SELECT 
FROM ai_prompts

    AND module = #{module}
    AND prompt_key = #{promptKey}
    AND is_active = #{isActive}

ORDER BY sort_order ASC, version DESC

mapper.update:
UPDATE ai_prompts
SET is_active = CASE WHEN version = #{version} THEN 1 ELSE 0 END
WHERE module = #{module} AND prompt_key = #{promptKey}
